SELECT COUNT(*) FROM ( SELECT pi.product_id, pi.lot_no, GREATEST( pi.inbound_qty - IFNULL(( SELECT SUM(po.outbound_qty) FROM product_outbound po WHERE po.product_id = pi.product_id AND po.lot_no = pi.lot_no ), 0), 0 ) AS stock_qty FROM product_inbound pi JOIN product p ON pi.product_id = p.product_id
(p.product_name LIKE CONCAT('%', #{keyword}, '%') OR pi.lot_no LIKE CONCAT('%', #{keyword}, '%'))
AND pi.reg_date >= #{startDate}
AND pi.reg_date <= #{endDate}
) AS tmp
stock_qty = 0
stock_qty < 50 AND stock_qty > 0
stock_qty >= 50

mapper.update:
UPDATE product_stock
SET stock_qty = GREATEST(stock_qty - #{qty}, 0)
WHERE product_id = #{productId} AND lot_no = #{lotNo}

mapper.select:
SELECT '입고' AS type, pi.inbound_qty AS qty, pi.reg_date AS reg_date, NULL AS client_name, '' AS memo, NULL AS cl_order_id FROM product_inbound pi WHERE pi.product_id = #{productId} AND pi.lot_no = #{lotNo}
UNION ALL
SELECT '출고' AS type, po.outbound_qty AS qty, po.outbound_date AS reg_date, c.client_name AS client_name, '' AS memo, cd.cl_order_id AS cl_order_id FROM product_outbound po LEFT JOIN client c ON po.client_id = c.client_id LEFT JOIN client_delivery cd ON cd.tracking_number = po.tracking_number WHERE po.product_id = #{productId} AND po.lot_no = #{lotNo}
ORDER BY reg_date ASC

SELECT COALESCE(SUM(reserved_qty), 0)
FROM stock_reservation
WHERE product_id = #{productId} AND lot_no = #{lotNo}

